create schema if not exists dam;
create schema if not exists pim;
create schema if not exists crm;
create schema if not exists plm;
create schema if not exists ingest;
create schema if not exists api;

create type app.app_name as enum ('dam', 'crm', 'pm', 'plm', 'admin');
create type app.app_role as enum ('administrator', 'sales', 'licensing', 'designer', 'viewer', 'vendor');
create type app.entity_status as enum ('active', 'inactive', 'archived', 'deleted');
create type app.source_confidence as enum ('verified', 'probable', 'possible', 'unmatched', 'rejected');
create type app.file_storage_provider as enum ('supabase', 'spaces', 'directus', 'external', 'local');
create type ingest.sync_status as enum ('pending', 'running', 'succeeded', 'failed', 'cancelled');

create or replace function app.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create or replace function app.jwt_role_names()
returns text[]
language sql
stable
as $$
  select coalesce(
    array(
      select lower(value::text)
      from jsonb_array_elements_text(
        coalesce(
          nullif(auth.jwt() -> 'app_metadata' -> 'roles', 'null'::jsonb),
          '[]'::jsonb
        )
      ) as value
    ),
    array[]::text[]
  );
$$;

create or replace function app.current_profile_id()
returns uuid
language sql
stable
security definer
set search_path = app, public
as $$
  select p.id
  from app.profile p
  where p.auth_user_id = auth.uid()
    and p.status = 'active'
  limit 1;
$$;

create or replace function app.has_role(required_role app.app_role)
returns boolean
language sql
stable
security definer
set search_path = app, public
as $$
  select exists (
    select 1
    from app.user_role ur
    join app.role r on r.id = ur.role_id
    where ur.profile_id = app.current_profile_id()
      and r.slug = required_role
      and ur.revoked_at is null
  )
  or lower(required_role::text) = any(app.jwt_role_names());
$$;

create or replace function app.has_any_role(required_roles app.app_role[])
returns boolean
language sql
stable
security definer
set search_path = app, public
as $$
  select exists (
    select 1
    from unnest(required_roles) as required_role
    where app.has_role(required_role)
  );
$$;

create or replace function app.has_app_access(required_app app.app_name)
returns boolean
language sql
stable
security definer
set search_path = app, public
as $$
  select app.has_role('administrator')
  or exists (
    select 1
    from app.app_access aa
    where aa.profile_id = app.current_profile_id()
      and aa.app = required_app
      and aa.revoked_at is null
  );
$$;

